  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import MentionNode from './components/HomePage/Editor/nodes/MentionNode.jsx';
  9→import Loader from './components/loadingComponent/BgLoader.jsx';
 10→import SeoManager from './seo/SeoManager.jsx';
 11→import ProtectedRoute from './components/ProtectedRoute.jsx';
 12→
 13→const NotFound = lazy(() => import('./components/NotFound.jsx'));
 14→
 15→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 16→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 17→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 18→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 19→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 20→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 21→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 22→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 23→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
