 87→  </LexicalComposer>
 88→);
 89→
 90→const SuspenseFallback = () => (
 91→  <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
 92→    <Loader />
 93→  </div>
 94→);
 95→
 96→const App = () => {
 97→
 98→  return (
 99→    <>
100→      <BrowserRouter>
101→        <SeoManager />
102→        <AppSplash />
103→        <Suspense fallback={<SuspenseFallback />}>
104→          <AppAuthModal/>
105→          <Routes>
106→            <Route path='/' element={<Navigate to='/home' replace/>}/>
107→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
108→            <Route path='/profile' element={<ProtectedRoute><MyProfile/></ProtectedRoute>}>
109→              <Route index element={<ProfilePostCards/>} />
110→              <Route path='media' element={<ProfileMediaSection/>} />
111→              <Route path='myOpinions' element={<MyOpinions/>}/>
112→              <Route path='stories' element={<ProfileStoriesSection/>}/>
113→            </Route>
114→
115→            <Route path='/visitProfile' element={<Visitprofile/>}>
116→              <Route index element={<VisitedProfilePostCards/>}/>
117→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
118→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
119→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
120→            </Route>
121→
122→            <Route path='/u/:username' element={<Visitprofile/>}>
123→              <Route index element={<VisitedProfilePostCards/>}/>
124→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
125→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
126→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
127→            </Route>
128→
129→            <Route path='/home' element={<HomeWithEditor/>}>
130→              <Route index element={<PostCards/>}/>
131→              <Route path='following' element={<PostCards/>}/>
132→              <Route path='for-you' element={<PostCards/>}/>
133→              <Route path='explore' element={<ExplorePage/>}/>
134→              <Route path='contentViewer' element={<ContentView/>}/>
135→              <Route path='post/:journalId' element={<ContentView/>}/>
136→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
137→              <Route path='bookmark' element={<Bookmarks/>}/>
138→              <Route path='opinions'element={<OpinionsPage/>}/>
139→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
140→
141→              <Route path='drafts' element={<DraftList/>}/>
142→              <Route path='analytics' element={<AnalyticsDashboard/>}/>
143→              <Route path='settings' element={<SettingsPage/>}/>
144→
145→              {/* Stories routes */}
146→              <Route path='stories' element={<StoryBrowser/>}/>
147→              <Route path='stories/library' element={<StoryLibrary/>}/>
148→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
149→              <Route path='stories/new' element={<StoryEditor/>}/>
150→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
151→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
152→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
153→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
154→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
155→
156→              {/* route for nested notifications */}
157→              <Route path='notifications' element={<Notifications/>}>
158→                <Route index element={<NotificationCards/>}/>
159→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
160→              </Route>
161→            </Route>
162→
163→            <Route path='/login' element={<LoginPage/>}/>
164→            <Route path='/signUp' element={<SignUp/>}/>
165→            <Route path='*' element={<NotFound/>}/>
166→          </Routes>
167→        </Suspense>
168→      </BrowserRouter>
169→    </>
170→  )
171→}
172→
173→export default App
