  9→const DraftList = () => {
 10→    const { session, user } = useAuth();
 11→    const userId = user?.userData?.[0]?.id || null;
 12→    const queryClient = useQueryClient();
 13→    const { handleOpenTextEditor } = useOutletContext();
 14→
 15→    const { data, isLoading } = useQuery({
 16→        queryKey: ['journal-drafts', userId],
 17→        queryFn: () => getDrafts(session?.access_token),
 18→        enabled: !!session?.access_token && !!userId,
 19→    });
 20→
 21→    const drafts = data?.data || [];
 22→
 23→    const handleResumeDraft = useCallback(async (draft) => {
 24→        try {
 25→            const result = await authedGet(
 26→                session?.access_token,
 27→                `/journal/${encodeURIComponent(draft.id)}/content`,
 28→                'failed to fetch draft content'
 29→            );
 30→            const journal = result?.journal;
 31→            if (journal) {
 32→                handleOpenTextEditor({
 33→                    draftId: draft.id,
 34→                    draftContent: journal.content,
 35→                    initialTitle: journal.title || '',
 36→                });
 37→            }
 38→        } catch (err) {
 39→            console.error('Failed to load draft:', err);
 40→        }
 41→    }, [handleOpenTextEditor, session?.access_token]);
 42→
 43→    const handleDeleteDraft = useCallback(async (e, draftId) => {
 44→        e.stopPropagation();
 45→        try {
 46→            await deleteJournal(draftId, session?.access_token);
 47→            queryClient.invalidateQueries({ queryKey: ['journal-drafts'] });
 48→        } catch (err) {
 49→            console.error('Failed to delete draft:', err);
 50→        }
 51→    }, [session?.access_token, queryClient]);
 52→
 53→    const formatDate = (dateStr) => {
 54→        if (!dateStr) return '';
 55→        const date = new Date(dateStr);
 56→        const now = new Date();
 57→        const diff = now - date;
 58→        const minutes = Math.floor(diff / 60000);
 59→        if (minutes < 60) return `${minutes}m ago`;
 60→        const hours = Math.floor(minutes / 60);
 61→        if (hours < 24) return `${hours}h ago`;
 62→        const days = Math.floor(hours / 24);
 63→        if (days < 7) return `${days}d ago`;
 64→        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
 65→    };
 66→
 67→    if (isLoading) {
 68→        return (
 69→            <div className="draft-list-container">
 70→                <h2 className="draft-list-title">Drafts</h2>
 71→                <div className="draft-list-loading">Loading drafts...</div>
 72→            </div>
 73→        );
 74→    }
 75→
 76→    return (
 77→        <div className="draft-list-container">
 78→            <h2 className="draft-list-title">Drafts</h2>
 79→
 80→            {drafts.length === 0 ? (
 81→                <div className="draft-list-empty">
 82→                    <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
 83→                        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
 84→                        <polyline points="14 2 14 8 20 8"/>
 85→                        <line x1="16" y1="13" x2="8" y2="13"/>
 86→                        <line x1="16" y1="17" x2="8" y2="17"/>
 87→                        <polyline points="10 9 9 9 8 9"/>
 88→                    </svg>
 89→                    <p>No drafts yet</p>
 90→                    <span>Start writing and your work will be saved automatically</span>
 91→                </div>
 92→            ) : (
 93→                <div className="draft-list-items">
 94→                    {drafts.map((draft) => (
 95→                        <div
 96→                            key={draft.id}
 97→                            className="draft-list-item"
 98→                            onClick={() => handleResumeDraft(draft)}
 99→                        >
100→                            <div className="draft-list-item-content">
101→                                <span className="draft-list-item-title">
102→                                    {draft.title?.trim() || 'Untitled'}
103→                                </span>
104→                                <span className="draft-list-item-date">
105→                                    Edited {formatDate(draft.updated_at || draft.created_at)}
106→                                </span>
107→                            </div>
108→                            <button
109→                                className="draft-list-item-delete"
110→                                onClick={(e) => handleDeleteDraft(e, draft.id)}
111→                                aria-label="Delete draft"
112→                                title="Delete draft"
113→                            >
114→                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
115→                                    <polyline points="3 6 5 6 21 6"/>
116→                                    <path d="M19 6l-2 14H7L5 6"/>
117→                                    <path d="M10 11v6"/>
118→                                    <path d="M14 11v6"/>
119→                                    <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
120→                                </svg>
121→                            </button>
122→                        </div>
123→                    ))}
124→                </div>
125→            )}
126→        </div>
127→    );
128→};
129→
130→export default DraftList;
